import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, Menu, X, User, Heart, Home } from 'lucide-react';

const Navbar = () => {
  const [isSearchActive, setIsSearchActive] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const desktopSearchInputRef = useRef(null);
  const mobileSearchInputRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  const cartItems = useSelector((state) => state.cart?.items || []);
  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  const categories = [
    { name: 'Living Room', sub: ['Sofas', 'TV Units', 'Coffee Tables', 'Bookshelves', 'Shoe Racks'] },
    { name: 'Bedroom', sub: ['Beds', 'Wardrobes', 'Dressers', 'Nightstands', 'Mattresses'] }
  ];

  // Close search dropdown and mobile menu automatically when navigating to a new page
  useEffect(() => {
    setIsSearchActive(false);
    setIsMenuOpen(false);
  }, [location.pathname]);

  // Desktop Search Submit
  const handleDesktopSearchSubmit = (e) => {
    e.preventDefault();
    if (desktopSearchInputRef.current?.value.trim()) {
      navigate(`/products?search=${encodeURIComponent(desktopSearchInputRef.current.value)}`);
      desktopSearchInputRef.current.value = '';
    }
  };

  // Mobile Search Logic (Dropdown Drop/Submit)
  const handleMobileSearchSubmit = (e) => {
    e.preventDefault();
    if (mobileSearchInputRef.current?.value.trim()) {
      navigate(`/products?search=${encodeURIComponent(mobileSearchInputRef.current.value)}`);
      setIsSearchActive(false);
      mobileSearchInputRef.current.value = '';
    }
  };

  // Toggle for mobile search drop-down
  const toggleMobileSearch = () => {
    setIsSearchActive(!isSearchActive);
    if (!isSearchActive) {
      setTimeout(() => {
        mobileSearchInputRef.current?.focus();
      }, 150);
    }
  };

  return (
    <>
      <header className="w-full bg-white shadow-sm sticky top-0 z-50">
        {/* Top Promotional Banner */}
        <div className="w-full bg-gray-50 py-1.5 border-b border-gray-200">
          <p className="text-center text-xs md:text-sm text-gray-700">
            Free Shipping on Orders Above ₹10,000 | <span className="text-orange-500 font-semibold">Use Code: VIDEM10</span>
          </p>
        </div>

        {/* Main Navbar Header */}
        <div className="container mx-auto px-4 py-3 relative flex items-center justify-between">

          {/* 1. Mobile Hamburger Menu Button (Left) */}
          <button
            className="md:hidden p-1 z-20 text-gray-700 hover:text-orange-500 transition-colors"
            onClick={() => setIsMenuOpen(true)}
            aria-label="Menu"
          >
            <Menu size={26} />
          </button>

          {/* 2. Brand Name (Centered exactly on Mobile, Left on Desktop) */}
          <Link
            to="/"
            className="absolute left-1/2 -translate-x-1/2 md:static md:translate-x-0 z-10 flex items-center gap-2"
          >
            <h1 className="text-xl md:text-2xl font-bold tracking-tight whitespace-nowrap">
              <span className="text-gray-900">Videm's</span> <span className="text-orange-500">Gallery</span>
            </h1>
          </Link>

          {/* 3. DESKTOP Permanent Search Bar (Hidden on Mobile) */}
          <form
            onSubmit={handleDesktopSearchSubmit}
            className="hidden md:flex flex-1 max-w-2xl mx-8 h-10"
          >
            <input
              ref={desktopSearchInputRef}
              type="text"
              placeholder="Search for furniture and more..."
              className="flex-1 h-full bg-gray-100 text-sm text-gray-800 outline-none rounded-l-md px-4 focus:ring-1 focus:ring-orange-500 transition-all"
            />
            <button
              type="submit"
              className="h-10 w-12 flex-shrink-0 flex items-center justify-center bg-orange-500 text-white rounded-r-md hover:bg-orange-600 transition-colors"
              aria-label="Search"
            >
              <Search size={20} />
            </button>
          </form>

          {/* 4. Right Side Navigation Icons */}
          <div className="flex items-center gap-3 z-20 bg-white">

            {/* MOBILE Icons (Hidden on Desktop) */}
            <div className="flex md:hidden items-center gap-4">
              {/* Search Toggle Button */}
              <button
                onClick={toggleMobileSearch}
                className="h-9 w-9 flex items-center justify-center bg-orange-500 text-white rounded-md transition-colors shadow-sm"
                aria-label="Toggle Search"
              >
                <Search size={18} />
              </button>

              {/* Profile Icon (Redirects to Login) */}
              <Link to="/login" className="p-1 text-gray-700 hover:text-orange-500 transition-colors" aria-label="Profile">
                <User size={24} />
              </Link>
            </div>

            {/* DESKTOP Icons (Hidden on Mobile) */}
            <div className="hidden md:flex items-center space-x-6 lg:space-x-8 flex-shrink-0">
              <Link to="/login" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors">
                <User size={24} />
                <span className="text-[10px] font-bold tracking-wider uppercase">Profile</span>
              </Link>

              <Link to="/wishlist" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors">
                <Heart size={24} />
                <span className="text-[10px] font-bold tracking-wider uppercase">Wishlist</span>
              </Link>

              <Link to="/cart" className="flex flex-col items-center gap-1 text-gray-700 hover:text-orange-500 transition-colors relative">
                <div className="relative">
                  <ShoppingCart size={24} />
                  {cartCount > 0 && (
                    <span className="absolute -top-2 -right-2 bg-orange-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                      {cartCount > 99 ? '99+' : cartCount}
                    </span>
                  )}
                </div>
                <span className="text-[10px] font-bold tracking-wider uppercase">Cart</span>
              </Link>
            </div>
          </div>
        </div>

        {/* MOBILE Dropdown Search Bar */}
        {/* Placed gracefully below the header so it never disrupts the logo */}
        <div
          className={`md:hidden absolute top-full left-0 w-full bg-white border-t border-gray-100 shadow-md p-3 transition-all duration-300 origin-top ${isSearchActive ? 'scale-y-100 opacity-100' : 'scale-y-0 opacity-0 pointer-events-none'
            }`}
        >
          <form onSubmit={handleMobileSearchSubmit} className="flex items-center h-10 w-full">
            <input
              ref={mobileSearchInputRef}
              type="text"
              placeholder="Search for furniture..."
              className="flex-1 h-full bg-gray-100 text-sm text-gray-800 outline-none rounded-l-md px-4 focus:ring-1 focus:ring-orange-500"
            />
            <button
              type="submit"
              className="h-10 w-12 flex-shrink-0 flex items-center justify-center bg-orange-500 text-white rounded-r-md hover:bg-orange-600 transition-colors"
            >
              <Search size={20} />
            </button>
          </form>
        </div>

        {/* Desktop Category Links */}
        <div className="hidden md:block w-full border-t border-gray-100 bg-white">
          <div className="container mx-auto px-4 py-3">
            <ul className="flex items-center justify-center space-x-12">
              {['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'].map((category) => (
                <li key={category}>
                  <Link to={`/products?category=${category.toLowerCase().replace(' ', '-')}`} className="text-sm font-bold text-gray-800 hover:text-orange-500 tracking-wide transition-colors">
                    {category}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </header>

      {/* Mobile Sidebar Drawer */}
      {isMenuOpen && (
        <div className="fixed inset-0 bg-white z-50 md:hidden flex flex-col shadow-2xl">
          <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <button onClick={() => setIsMenuOpen(false)} className="text-gray-700 hover:text-orange-500 transition-colors">
              <X size={28} />
            </button>
            <h1 className="text-xl font-bold tracking-tight text-gray-900">
              Videm's <span className="text-orange-500">Gallery</span>
            </h1>
            <div className="w-7"></div> {/* Spacer for perfect flex-between centering */}
          </div>

          <div className="flex-1 overflow-y-auto p-6 pb-24">
            {categories.map((cat) => (
              <div key={cat.name} className="mb-8">
                <h2 className="text-lg font-semibold text-gray-900 mb-4">{cat.name}</h2>
                <ul className="space-y-4 ml-4 text-gray-600">
                  {cat.sub.map((sub) => (
                    <li key={sub}>
                      <Link
                        to={`/products?category=${sub.toLowerCase().replace(' ', '-')}`}
                        onClick={() => setIsMenuOpen(false)}
                        className="block w-full hover:text-orange-500 transition-colors"
                      >
                        {sub}
                      </Link>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* MOBILE Bottom Navigation (Fixed at bottom of viewport) */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 z-40 pb-2 pt-2">
        <div className="flex items-center justify-around">
          <Link to="/" className="flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16">
            <Home size={22} />
            <span className="text-[10px] font-medium">Home</span>
          </Link>

          <button onClick={toggleMobileSearch} className="flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16">
            <Search size={22} />
            <span className="text-[10px] font-medium">Search</span>
          </button>

          <Link to="/wishlist" className="flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16">
            <Heart size={22} />
            <span className="text-[10px] font-medium">Wishlist</span>
          </Link>

          <Link to="/cart" className="flex flex-col items-center gap-1 text-gray-500 hover:text-orange-500 transition-colors w-16 relative">
            <ShoppingCart size={22} />
            {cartCount > 0 && (
              <span className="absolute -top-1 right-2 bg-red-600 text-white text-[10px] font-bold h-4 w-4 rounded-full flex items-center justify-center">
                {cartCount > 99 ? '99+' : cartCount}
              </span>
            )}
            <span className="text-[10px] font-medium">Cart</span>
          </Link>
        </div>
      </div>
    </>
  );
};

export default Navbar;
